import json
from datetime import datetime

filename = "./runtime_data/2024-01-01_to_2024-03-31_order.json"

with open(filename, 'r') as f:
    data = json.load(f)

# 1. Total revenue for the quarter
total_revenue = 0

# 2. Total revenue per month
monthly_revenue = {
    "January": 0,
    "February": 0,
    "March": 0
}

for order in data:
    amount = float(order['node']['totalPriceSet']['shopMoney']['amount'])
    processed_at = order['node']['processedAt']
    date_obj = datetime.strptime(processed_at, "%Y-%m-%dT%H:%M:%SZ")
    month = date_obj.strftime("%B")

    total_revenue += amount

    if month == "January":
        monthly_revenue["January"] += amount
    elif month == "February":
        monthly_revenue["February"] += amount
    elif month == "March":
        monthly_revenue["March"] += amount

print(f"Total Revenue for Q1 2024: ${total_revenue:.2f}")
print("Monthly Revenue:")
for month, revenue in monthly_revenue.items():
    print(f"{month}: ${revenue:.2f}")

# 3. Monthly revenue trend
print("\nMonthly Revenue Trend:")
months = list(monthly_revenue.keys())
revenues = list(monthly_revenue.values())

if len(revenues) >= 2:
    if revenues[1] > revenues[0]:
        print(f"Revenue increased from {months[0]} to {months[1]}.")
    elif revenues[1] < revenues[0]:
        print(f"Revenue decreased from {months[0]} to {months[1]}.")
    else:
        print(f"Revenue remained the same from {months[0]} to {months[1]}.")

    if revenues[2] > revenues[1]:
        print(f"Revenue increased from {months[1]} to {months[2]}.")
    elif revenues[2] < revenues[1]:
        print(f"Revenue decreased from {months[1]} to {months[2]}.")
    else:
        print(f"Revenue remained the same from {months[1]} to {months[2]}.")
else:
    print("Not enough months to determine a trend.")

